#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    if(!(cin >> n)) return 0;
    vector<int> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    int i = n - 2;
    while(i >= 0 && nums[i] >= nums[i + 1]) i--;
    if(i < 0){
        sort(nums.begin(), nums.end());
    } else {
        int j = n - 1;
        while(nums[j] <= nums[i]) j--;
        swap(nums[i], nums[j]);
        sort(nums.begin() + i + 1, nums.end());
    }
    for(int i = 0; i < n; i++) cout << nums[i] << ' ';
}
